mapper.insert:

    SELECT seq_board_post.nextval FROM dual

INSERT INTO apt_board_post (    /*kr.or.ddit.domain.apt.board.free.mapper.IResidentBoardMapper.insertBoardFree*/
post_no
,board_no
,ttl
,cn
,wrtr_id
,prrt_cd
,reg_dttm
,mdf_dttm
,inq_cnt
,del_yn
,atch_file_id
,opn_yn
) VALUES (
#{postNo}
,#{boardNo}
,#{ttl}
,#{cn}
,#{wrtrId}
,#{prrtCd}
,SYSDATE
,SYSDATE
,0
,'N'
,#{atchFileId}
,NVL(#{opnYn}, 'Y')
)

mapper.update:
UPDATE apt_board_comment    /*kr.or.ddit.domain.apt.board.free.mapper.IResidentBoardMapper.deleteBoardComment*/
   SET del_yn = 'Y'
 WHERE cmt_no = #{cmtNo}

UPDATE apt_board_post       /*kr.or.ddit.domain.apt.board.free.mapper.IResidentBoardMapper.deleteBoardFree*/
SET del_yn = 'Y'
WHERE post_no = #{postNo}

UPDATE apt_board_post       /*kr.or.ddit.domain.apt.board.free.mapper.IResidentBoardMapper.updateBoardFree*/
SET ttl = #{ttl}
    ,cn = #{cn}
    ,mdf_dttm = SYSDATE
WHERE post_no = #{postNo}

UPDATE apt_board_post       /*kr.or.ddit.domain.apt.board.free.mapper.IResidentBoardMapper.updateInqCnt*/
SET inq_cnt = inq_cnt + 1
WHERE post_no = #{postNo}

mapper.insert:

SELECT seq_board_comment.nextval FROM dual

INSERT INTO apt_board_comment (     /*kr.or.ddit.domain.apt.board.free.mapper.IResidentBoardMapper.insertBoardComment*/
cmt_no
,post_no
,cmt_group
,cmt_cn
,cmt_sort_ord
,reg_dttm
,del_yn
,mdf_dttm
,user_no
) VALUES (
#{cmtNo}
,#{postNo}
,#{cmtNo}
,#{cmtCn}
,0
,SYSDATE
,'N'
,SYSDATE
,#{userNo}
)
